async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const productTile = await browser.extractComponent<{ name: string; price: string; detailsLinkSelector: string }>(
        {
            typeName: 'ProductTile',
            schema: '{ name: string; price: string; detailsLinkSelector: string; }'
        },
        params.productName
    );
    if (!productTile || !productTile.detailsLinkSelector) {
        throw new Error('Could not find product: ' + params.productName);
    }
    await browser.click(productTile.detailsLinkSelector);
    await browser.awaitPageLoad();
    return { success: true, message: 'Navigated to ' + productTile.name };
}
